```class Solution {
public:
    int findBestValue(vector<int>& arr, int target) {
        int n = arr.size();
        sort(arr.begin(), arr.end());
        int prefixSum[n + 1];
        prefixSum[0] = 0;
        for (int i = 0; i < n; i++) {
            prefixSum[i + 1] = prefixSum[i] + arr[i];
        }
        int res = arr[0], diff = INT_MAX;
        for (int i = 0; i < n; i++) {
            int val = (target - prefixSum[i]) / (n - i);
            int val1 = val, val2 = val + 1;
            int sum1 = prefixSum[i] + val * (n - i), sum2 = prefixSum[i] + val2 * (n - i);
            if (abs(sum1 - target) <= abs(sum2 - target)) {
                if (abs(sum1 - target) < diff) {
                    diff = abs(sum1 - target);
                    res = val;
                }
            } else {
                if (abs(sum2 - target) < diff) {
                    diff = abs(sum2 - target);
                    res = val2;
                }
            }
        }
        return res;
    }
};
